#include <iostream>
using namespace std;

bool isPrime(int n) {
    if (n < 2) return false;
    for (int i = 2; i * i <= n; ++i) {
        if (n % i == 0) return false;
    }
    return true;
}

int fib(int n) {
    if (n == 1 || n == 2) return 1;
    return fib(n - 1) + fib(n - 2);
}

int main() {
    int n;
    cin >> n;
    cout << (isPrime(n) ? "prime" : "not prime") << endl;
    cout << fib(n) << endl;
    return 0;
}

概念题：值传递和引用传递都会把实参信息传给形参；值传递形参是副本，修改形参不影响实参；引用传递形参是实参别名，修改形参会影响实参且可避免大对象复制。重载函数主要通过参数个数、参数类型和参数顺序区分，不能只靠返回值区分。

#include <iostream>
using namespace std;
class Rectangle {
private:
    double width, height;
public:
    Rectangle(double w = 0, double h = 0) : width(w), height(h) {}
    Rectangle(const Rectangle& other) : width(other.width), height(other.height) {}
    ~Rectangle() {}
    double perimeter() const { return 2 * (width + height); }
    double area() const { return width * height; }
};
int main() {
    Rectangle r1(3, 4);
