#include <iostream>
using namespace std;

class Cube {
    double length;
public:
    Cube(double l = 0) : length(l) {}
    double area() const { return 6 * length * length; }
    double volume() const { return length * length * length; }
    bool sameByMember(const Cube& other) const {
        return length == other.length;
    }
    double getLength() const { return length; }
};

bool sameByGlobal(const Cube& a, const Cube& b) {
    return a.getLength() == b.getLength();
}

int main() {
    Cube c1(3), c2(3);
    cout << c1.area() << " " << c1.volume() << endl;
    cout << c1.sameByMember(c2) << " " << sameByGlobal(c1, c2) << endl;
    return 0;
}

#include <iostream>
using namespace std;

class Point {
    double x, y;
public:
    void set(double x0, double y0) { x = x0; y = y0; }
    double getX() const { return x; }
    double getY() const { return y; }
};

class Circle {
    Point center;
    double radius;
public:
    void set(Point c, double r) { center = c; radius = r; }
    bool containsByMember(const Point& p) const {
        double dx = p.getX() - center.getX();
        double dy = p.getY() - center.getY();
        return dx * dx + dy * dy <= radius * radius;
    }
    Point getCenter() const { return center; }
    double getRadius() const { return radius; }
};

bool containsByGlobal(const Circle& c, const Point& p) {
    double dx = p.getX() - c.getCenter().getX();
    double dy = p.getY() - c.getCenter().getY();
    return dx * dx + dy * dy <= c.getRadius() * c.getRadius();
}

int main() {
    Point center, p;
    center.set(0, 0);
    p.set(1, 1);
    Circle circle;
    circle.set(center, 2);
    cout << circle.containsByMember(p) << " " << containsByGlobal(circle, p) << endl;
    return 0;
}

