class Rectangle {
    Point leftBottom, rightTop;
public:
    Rectangle(Point lb, Point rt) : leftBottom(lb), rightTop(rt) {}
    Rectangle(const Rectangle& r)
        : leftBottom(r.leftBottom), rightTop(r.rightTop) {}
    double area() const {
        return fabs((rightTop.getX() - leftBottom.getX()) *
                    (rightTop.getY() - leftBottom.getY()));
    }
};
