#include <iostream>
#include <string>
using namespace std;

void concatCharArray(char a[], const char b[]) {
    int i = 0, j = 0;
    while (a[i] != '\0') ++i;
    while (b[j] != '\0') {
        a[i++] = b[j++];
    }
    a[i] = '\0';
}

int main() {
    char s1[200] = "hello";
    char s2[] = "cpp";
    concatCharArray(s1, s2);
    cout << s1 << endl;

    string a = "hello", b = "cpp";
    a += b;
    cout << a << endl;
    return 0;
}

#include <iostream>
using namespace std;
class SimpleCircle {
private:
    int *itsRadius;
public:
    SimpleCircle(int r = 0) : itsRadius(new int(r)) {}
    SimpleCircle(const SimpleCircle& other)
        : itsRadius(new int(*other.itsRadius)) {}
    ~SimpleCircle() { delete itsRadius; }
    SimpleCircle& operator=(const SimpleCircle& other) {
        if (this != &other) {
            *itsRadius = *other.itsRadius;
        }
        return *this;
    }
    int getRadius() const { return *itsRadius; }
    void setRadius(int r) { *itsRadius = r; }
    double area() const { return 3.14159 * (*itsRadius) * (*itsRadius); }
};
int main() {
    SimpleCircle c1(5);
    SimpleCircle c2(c1);
    c2.setRadius(10);
    cout << c1.getRadius() << " " << c2.getRadius() << endl;
    cout << c1.area() << " " << c2.area() << endl;
    return 0;
}

